class Solution:
    def validateBinaryTreeNodes(self, n: int, leftChild, rightChild) -> bool:
        in_degree = [0] * n
        for i in range(n):
            if leftChild[i] != -1:
                in_degree[leftChild[i]] += 1
                if in_degree[leftChild[i]] > 1:
                    return False
            if rightChild[i] != -1:
                in_degree[rightChild[i]] += 1
                if in_degree[rightChild[i]] > 1:
                    return False
        roots = [i for i in range(n) if in_degree[i] == 0]
        if len(roots) != 1:
            return False
        visited = set()
        queue = [roots[0]]
        while queue:
            node = queue.pop()
            if node in visited:
                return False
            visited.add(node)
            if leftChild[node] != -1:
                queue.append(leftChild[node])
            if rightChild[node] != -1:
                queue.append(rightChild[node])
        return len(visited) == n

