var validateBinaryTreeNodes = function(n, leftChild, rightChild) {
    const inDeg = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        if (leftChild[i] !== -1) { inDeg[leftChild[i]]++; if (inDeg[leftChild[i]] > 1) return false; }
        if (rightChild[i] !== -1) { inDeg[rightChild[i]]++; if (inDeg[rightChild[i]] > 1) return false; }
    }
    const roots = [];
    for (let i = 0; i < n; i++) if (inDeg[i] === 0) roots.push(i);
    if (roots.length !== 1) return false;
    const visited = new Set();
    const stack = [roots[0]];
    while (stack.length) {
        const node = stack.pop();
        if (visited.has(node)) return false;
        visited.add(node);
        if (leftChild[node] !== -1) stack.push(leftChild[node]);
        if (rightChild[node] !== -1) stack.push(rightChild[node]);
    }
    return visited.size === n;
};
